package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.ExclusionStrategy;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

class ExcluderTest {

    private Excluder excluder;

    @BeforeEach
    void setUp() {
        excluder = new Excluder();
    }

    @Test
    void excludeClass_excludeClassChecksTrue() throws Exception {
        // We spy excluder to mock private excludeClassChecks method to return true
        Excluder spyExcluder = Mockito.spy(excluder);

        // Mock excludeClassChecks to return true
        doReturn(true).when(spyExcluder).getClass()
                .getDeclaredMethod("excludeClassChecks", Class.class)
                .invoke(spyExcluder, String.class);

        // Use reflection to mock excludeClassChecks
        // Since direct mocking private method is complicated, we mock excludeClassChecks via spy and doReturn using reflection
        // Instead, we can use partial mocking by overriding excludeClassChecks via spy
        // But excludeClassChecks is private, so we use doReturn with method name and parameters

        // Alternative: Use reflection to set excludeClassChecks accessible and invoke normally
        // But we want to test excludeClass with excludeClassChecks returning true

        // Instead, we create a subclass to override excludeClassChecks for testing
        Excluder excluderWithExcludeClassChecksTrue = new Excluder() {
            @Override
            public boolean excludeClassChecks(Class<?> clazz) {
                return true;
            }
        };

        boolean result = excluderWithExcludeClassChecksTrue.excludeClass(String.class, true);
        assertTrue(result);
    }

    @Test
    void excludeClass_excludeClassChecksFalse_excludeClassInStrategyTrue() throws Exception {
        // Create subclass to override excludeClassChecks to false and excludeClassInStrategy to true
        Excluder excluderMock = new Excluder() {
            @Override
            public boolean excludeClassChecks(Class<?> clazz) {
                return false;
            }

            @Override
            public boolean excludeClassInStrategy(Class<?> clazz, boolean serialize) {
                return true;
            }
        };

        boolean result = excluderMock.excludeClass(String.class, false);
        assertTrue(result);
    }

    @Test
    void excludeClass_excludeClassChecksFalse_excludeClassInStrategyFalse() throws Exception {
        // Create subclass to override excludeClassChecks to false and excludeClassInStrategy to false
        Excluder excluderMock = new Excluder() {
            @Override
            public boolean excludeClassChecks(Class<?> clazz) {
                return false;
            }

            @Override
            public boolean excludeClassInStrategy(Class<?> clazz, boolean serialize) {
                return false;
            }
        };

        boolean result = excluderMock.excludeClass(String.class, true);
        assertFalse(result);
    }

    @Test
    void excludeClass_withRealExcludeClassChecksAndExcludeClassInStrategy() throws Exception {
        // We test with real excludeClassChecks and excludeClassInStrategy, so we need to set up Excluder state

        // Use reflection to set serializationStrategies and deserializationStrategies to lists containing mock ExclusionStrategy

        ExclusionStrategy serializationStrategy = mock(ExclusionStrategy.class);
        when(serializationStrategy.shouldSkipClass(String.class)).thenReturn(false);
        ExclusionStrategy deserializationStrategy = mock(ExclusionStrategy.class);
        when(deserializationStrategy.shouldSkipClass(String.class)).thenReturn(true);

        setField(excluder, "serializationStrategies", Collections.singletonList(serializationStrategy));
        setField(excluder, "deserializationStrategies", Collections.singletonList(deserializationStrategy));

        // Test serialize = true, excludeClassInStrategy should return false (serializationStrategy returns false)
        boolean serializeResult = excluder.excludeClass(String.class, true);
        // excludeClassChecks returns false for String.class (real method)
        // excludeClassInStrategy returns false because serializationStrategy.shouldSkipClass returns false
        assertFalse(serializeResult);

        // Test serialize = false, excludeClassInStrategy should return true (deserializationStrategy returns true)
        boolean deserializeResult = excluder.excludeClass(String.class, false);
        assertTrue(deserializeResult);
    }

    // Helper method to set private fields via reflection
    private static void setField(Object target, String fieldName, Object value) throws Exception {
        Field field = Excluder.class.getDeclaredField(fieldName);
        field.setAccessible(true);
        field.set(target, value);
    }
}
